(() => {
  const buildViolation = (id, impact, description, help, node) => ({
    id,
    impact,
    description,
    help,
    helpUrl: `https://www.w3.org/WAI/WCAG21/quickref/#${id}`,
    tags: ["wcag2a", "wcag2aa"],
    nodes: [{ html: node.outerHTML, target: [node.tagName.toLowerCase()] }],
  });

  const run = async () => {
    const violations = [];

    document.querySelectorAll("img").forEach((img) => {
      if (!img.getAttribute("alt")) {
        violations.push(
          buildViolation(
            "non-text-content",
            "serious",
            "Images must have alternate text",
            "Add meaningful alt text to images",
            img,
          ),
        );
      }
    });

    document.querySelectorAll("button, a, input, select, textarea").forEach((el) => {
      const label = el.getAttribute("aria-label") || el.textContent?.trim();
      if (!label) {
        violations.push(
          buildViolation(
            "name-role-value",
            "moderate",
            "Interactive elements must have an accessible name",
            "Provide an accessible label",
            el,
          ),
        );
      }
    });

    document.querySelectorAll("[style]").forEach((el) => {
      const style = el.getAttribute("style") || "";
      if (style.includes("color:") && style.includes("background:")) {
        violations.push(
          buildViolation(
            "color-contrast",
            "serious",
            "Elements should have sufficient contrast",
            "Ensure text meets WCAG contrast ratios",
            el,
          ),
        );
      }
    });

    return { violations, passes: [], incomplete: [], inapplicable: [] };
  };

  window.axe = { run };
})();
